import{c as o,Q as a,j as l,m as c}from"./chunks/framework.iD28w_5a.js";const k=JSON.parse('{"title":"fork / execve / waitpid","description":"","frontmatter":{},"headers":[],"relativePath":"document/kernel/proc/fork_exec.md","filePath":"document/kernel/proc/fork_exec.md","lastUpdated":1777209094000}'),i={name:"document/kernel/proc/fork_exec.md"};function r(d,e,p,t,s,n){return a(),l("div",null,[...e[0]||(e[0]=[c('<h1 id="fork-execve-waitpid" tabindex="-1">fork / execve / waitpid <a class="header-anchor" href="#fork-execve-waitpid" aria-label="Permalink to &quot;fork / execve / waitpid&quot;">​</a></h1><blockquote><p>里程碑: <code>034_process_fork_exec</code> (子迭代 2-4)</p></blockquote><h2 id="功能概述" tabindex="-1">功能概述 <a class="header-anchor" href="#功能概述" aria-label="Permalink to &quot;功能概述&quot;">​</a></h2><p>完整的 Unix 风格进程创建与执行机制。<code>fork()</code> 通过 Copy-on-Write 复制页表，<code>execve()</code> 从 VFS 加载新 ELF 替换地址空间，<code>waitpid()</code> 回收子进程。</p><h2 id="fork-—-cow-页表复制" tabindex="-1">fork() — CoW 页表复制 <a class="header-anchor" href="#fork-—-cow-页表复制" aria-label="Permalink to &quot;fork() — CoW 页表复制&quot;">​</a></h2><h3 id="流程-kernel-proc-process-cpp" tabindex="-1">流程 (<code>kernel/proc/process.cpp</code>) <a class="header-anchor" href="#流程-kernel-proc-process-cpp" aria-label="Permalink to &quot;流程 (`kernel/proc/process.cpp`)&quot;">​</a></h3><ol><li>复制当前 TCB → 分配新 PID</li><li>CoW 复制页表: 标记所有 PTE 只读</li><li>继承文件描述符表</li><li>子进程返回 0，父进程返回 child PID</li></ol><h3 id="cow-缺页处理" tabindex="-1">CoW 缺页处理 <a class="header-anchor" href="#cow-缺页处理" aria-label="Permalink to &quot;CoW 缺页处理&quot;">​</a></h3><ul><li>page fault handler 检测: 只读 PTE + CoW 标记</li><li>分配新物理页 → 复制内容 → 更新 PTE 为可写 → 清除 CoW 标记</li></ul><h2 id="execve-—-elf-加载" tabindex="-1">execve() — ELF 加载 <a class="header-anchor" href="#execve-—-elf-加载" aria-label="Permalink to &quot;execve() — ELF 加载&quot;">​</a></h2><h3 id="流程-kernel-proc-process-cpp-1" tabindex="-1">流程 (<code>kernel/proc/process.cpp</code>) <a class="header-anchor" href="#流程-kernel-proc-process-cpp-1" aria-label="Permalink to &quot;流程 (`kernel/proc/process.cpp`)&quot;">​</a></h3><ol><li>从 VFS 读取 ELF 文件</li><li>解析 program headers</li><li>加载到地址空间 (新的 <code>AddressSpace</code>)</li><li>设置入口点</li><li>清理旧映射</li></ol><h2 id="waitpid-—-子进程回收" tabindex="-1">waitpid() — 子进程回收 <a class="header-anchor" href="#waitpid-—-子进程回收" aria-label="Permalink to &quot;waitpid() — 子进程回收&quot;">​</a></h2><h3 id="流程-kernel-syscall-sys-waitpid-hpp-cpp" tabindex="-1">流程 (<code>kernel/syscall/sys_waitpid.hpp/cpp</code>) <a class="header-anchor" href="#流程-kernel-syscall-sys-waitpid-hpp-cpp" aria-label="Permalink to &quot;流程 (`kernel/syscall/sys_waitpid.hpp/cpp`)&quot;">​</a></h3><ol><li>父进程阻塞等待指定子进程退出</li><li>收集 <code>exit_status</code></li><li>清理子进程 TCB (防 zombie)</li></ol><h3 id="进程状态" tabindex="-1">进程状态 <a class="header-anchor" href="#进程状态" aria-label="Permalink to &quot;进程状态&quot;">​</a></h3><ul><li><code>Zombie</code>: 子进程已退出，等待父进程 <code>waitpid</code> 回收</li><li><code>Dead</code>: TCB 已清理完毕</li></ul><h2 id="系统调用" tabindex="-1">系统调用 <a class="header-anchor" href="#系统调用" aria-label="Permalink to &quot;系统调用&quot;">​</a></h2><ul><li><code>SYS_fork</code> — 创建子进程</li><li><code>SYS_execve</code> — 替换进程映像</li><li><code>SYS_waitpid</code> — 等待子进程</li><li><code>SYS_exit</code> — 终止当前进程</li></ul><h2 id="源码位置" tabindex="-1">源码位置 <a class="header-anchor" href="#源码位置" aria-label="Permalink to &quot;源码位置&quot;">​</a></h2><ul><li><code>kernel/proc/process.hpp/cpp</code> — fork/execve 实现</li><li><code>kernel/syscall/sys_fork.cpp</code> — fork 系统调用</li><li><code>kernel/syscall/sys_exit.cpp</code> — exit 系统调用</li><li><code>kernel/syscall/sys_waitpid.hpp/cpp</code> — waitpid 系统调用</li><li><code>kernel/proc/elf_types.hpp/cpp</code> — ELF 类型定义</li></ul>',21)])])}const u=o(i,[["render",r]]);export{k as __pageData,u as default};
